import{_ as a,c as e,o as r,ag as l}from"./chunks/framework.B-XtCDNB.js";const h=JSON.parse('{"title":"6. Libraries","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/programming-language/main/06-00-libraries.md","filePath":"tutorials/programming-language/main/06-00-libraries.md","lastUpdated":1776620988000}'),s={name:"tutorials/programming-language/main/06-00-libraries.md"};function t(n,i,o,c,g,d){return r(),e("div",null,[...i[0]||(i[0]=[l('<h1 id="_6-libraries" tabindex="-1">6. Libraries <a class="header-anchor" href="#_6-libraries" aria-label="Permalink to &quot;6. Libraries&quot;">​</a></h1><p>At the system level, a Vala library is exactly a C library, and so the same tools are used. In order to make the process simpler, and so that the Vala compiler can understand the process there is then an extra level of Vala specific information.</p><p>A &quot;Vala library&quot; is therefore, the system part:</p><ul><li>A system library (e.g. <code>libgee.so</code>)</li><li>A <code>pkg-config</code> entry (e.g. <code>gee-0.8.pc</code>)</li></ul><p>Both of which are installed in the standard locations. And the Vala specific files:</p><ul><li>A VAPI file (e.g. <code>gee-0.8.vapi</code>)</li><li>An optional dependency file (e.g. <code>gee-0.8.deps</code>)</li></ul><p>These files are explained later in this section. It should be noted that the library names are the same in the Vala specific files as in the <code>pkg-config</code> files.</p><ul class="section-toc"><li><a href="06-00-libraries/06-01-using-libraries">6.1. Using Libraries</a></li><li><a href="06-00-libraries/06-02-creating-a-library">6.2. Creating a Library</a><ul class="section-toc section-toc-sub"><li><a href="06-00-libraries/06-02-creating-a-library#_6-2-1-compilation-and-linking-using-command-line">6.2.1. Compilation and linking using Command Line</a></li></ul></li><li><a href="06-00-libraries/06-03-binding-libraries-with-vapi-files">6.3. Binding Libraries with VAPI Files</a></li><li><a href="06-00-libraries/06-04-abi-and-api-design-choices">6.4. ABI and API Design Choices</a><ul class="section-toc section-toc-sub"><li><a href="06-00-libraries/06-04-abi-and-api-design-choices#_6-4-1-abi">6.4.1. ABI</a></li><li><a href="06-00-libraries/06-04-abi-and-api-design-choices#_6-4-2-api-design">6.4.2. API Design</a></li><li><a href="06-00-libraries/06-04-abi-and-api-design-choices#_6-4-3-further-reading">6.4.3. Further Reading</a></li></ul></li><li><a href="06-00-libraries/06-05-binding-to-vala-libraries-from-other-languages">6.5. Binding to Vala Libraries from Other Languages</a><ul class="section-toc section-toc-sub"><li><a href="06-00-libraries/06-05-binding-to-vala-libraries-from-other-languages#_6-5-1-haskell">6.5.1. Haskell</a></li><li><a href="06-00-libraries/06-05-binding-to-vala-libraries-from-other-languages#_6-5-2-javascript">6.5.2. JavaScript</a></li><li><a href="06-00-libraries/06-05-binding-to-vala-libraries-from-other-languages#_6-5-3-lua">6.5.3. Lua</a></li><li><a href="06-00-libraries/06-05-binding-to-vala-libraries-from-other-languages#_6-5-4-perl">6.5.4. Perl</a></li><li><a href="06-00-libraries/06-05-binding-to-vala-libraries-from-other-languages#_6-5-5-python">6.5.5. Python</a></li><li><a href="06-00-libraries/06-05-binding-to-vala-libraries-from-other-languages#_6-5-6-rust">6.5.6. Rust</a></li></ul></li><li><a href="06-00-libraries/06-06-using-autotools">6.6. Using Autotools</a><ul class="section-toc section-toc-sub"><li><a href="06-00-libraries/06-06-using-autotools#_6-6-1-example">6.6.1. Example</a></li></ul></li></ul>',8)])])}const u=a(s,[["render",t]]);export{h as __pageData,u as default};
